INSERT INTO public.objectives (id,ticket_id,objective,created_at,updated_at,title,state,agent_identifier,model_identifier,completed_at,created_by,assigned_agent) VALUES ('ffffffff-1001-4000-8000-000000000001', 'bbbbbbbb-0000-4000-8000-000000000001', 'Configure GitHub Actions workflows for lint and test jobs.', DEFAULT, DEFAULT, 'CI workflow setup', 'complete', 'Claude', NULL, '2020-04-28T03:08:00.000Z', NULL, 'null'), ('ffffffff-1002-4000-8000-000000000002', 'bbbbbbbb-0000-4000-8000-000000000001', 'Add the deploy job and wire in production secrets.', DEFAULT, DEFAULT, 'Deployment wiring', 'complete', 'Claude', NULL, '2020-04-12T03:53:46.000Z', NULL, 'null'), ('ffffffff-1003-4000-8000-000000000003', 'bbbbbbbb-0000-4000-8000-000000000002', 'Define color, spacing, and typography tokens for the Alpha project.', DEFAULT, DEFAULT, 'Design system tokens', 'draft', NULL, NULL, '2020-05-05T16:19:28.000Z', NULL, 'null'), ('ffffffff-1004-4000-8000-000000000004', 'bbbbbbbb-0000-4000-8000-000000000003', 'Document all public REST endpoints with examples and error codes.', DEFAULT, DEFAULT, 'API documentation', 'draft', NULL, NULL, '2020-08-16T07:57:57.000Z', NULL, 'null'), ('ffffffff-1005-4000-8000-000000000005', 'bbbbbbbb-0000-4000-8000-000000000004', 'Add PostHog analytics to the Beta project and instrument key user flows.', DEFAULT, DEFAULT, 'Integrate analytics SDK', 'draft', NULL, NULL, '2020-06-22T18:07:14.000Z', NULL, 'null'), ('ffffffff-1006-4000-8000-000000000006', 'bbbbbbbb-0000-4000-8000-000000000005', 'Run axe-core across all pages and resolve WCAG AA violations.', DEFAULT, DEFAULT, 'Audit accessibility issues', 'draft', 'Codex', NULL, '2020-07-11T18:57:55.000Z', NULL, 'null'), ('ffffffff-1007-4000-8000-000000000007', 'bbbbbbbb-0000-4000-8000-000000000006', 'Write a one-time script to migrate records from the old schema to the new one.', DEFAULT, DEFAULT, 'Migrate legacy data', 'draft', NULL, NULL, '2020-03-19T02:44:50.000Z', NULL, 'null');
