INSERT INTO public.ticket_events (id,ticket_id,session_id,event_type,phase,summary,payload,is_blocking,created_at,created_by,objective_id) VALUES ('dddddddd-0000-4000-8000-000000000001', 'bbbbbbbb-0000-4000-8000-000000000001', NULL, 'deliver', 'review', 'Delivered the CI/CD workflow update for review.', '{"files_changed":2,"objective_titles":["CI workflow setup","Deployment wiring"]}', 'f', DEFAULT, NULL, NULL);
INSERT INTO public.file_changes (id,ticket_id,session_id,event_id,file_name,file_path,label,summary,why,impact,change_kind,attribution_source,confidence,hunks,created_at,updated_at,checkpoint_id,objective_id) VALUES ('eeeeeeee-0000-4000-8000-000000000001', 'bbbbbbbb-0000-4000-8000-000000000001', 'cccccccc-0000-4000-8000-000000000001', 'dddddddd-0000-4000-8000-000000000001', 'ci.yml', '.github/workflows/ci.yml', 'CI workflow updates', 'Added lint and test jobs with cached dependencies and fail-fast behavior.', 'This mirrors the first completed objective and gives the review card a concrete diff to inspect.', 'Improves pipeline feedback time and makes the review state feel like an in-progress deliverable.', 'modify', 'explicit', 'explicit', '[{"header":"@@ -1,8 +1,34 @@"}]', DEFAULT, DEFAULT, NULL, NULL), ('eeeeeeee-0000-4000-8000-000000000002', 'bbbbbbbb-0000-4000-8000-000000000001', 'cccccccc-0000-4000-8000-000000000001', 'dddddddd-0000-4000-8000-000000000001', 'deploy.yml', '.github/workflows/deploy.yml', 'Deploy workflow updates', 'Wired production secrets into the deploy job and gated releases on the main branch.', 'This mirrors the second completed objective and shows a second file in the same review batch.', 'Shows how the review ticket can carry multiple related file changes before merge.', 'modify', 'explicit', 'explicit', '[{"header":"@@ -0,0 +1,28 @@"}]', DEFAULT, DEFAULT, NULL, NULL);
INSERT INTO public.feed_posts (id,organization_id,project_id,ticket_id,session_id,agent_type,title,body,tags,impact_level,files_touched,tradeoffs,human_actions,source_event_ids,source_window_start,source_window_end,created_at,updated_at,tickets_created,objective_id,created_by,summary,objective_sections,orphan_file_changes,total_events,total_files,pending_actions,source_session_ids) VALUES ('eb2f39ef-dbf0-5ca6-9c6e-bd28d6aedea8', 1, 'aaaaaaaa-0000-4000-8000-000000000001', 'bbbbbbbb-0000-4000-8000-000000000001', NULL, NULL, 'CI/CD pipeline scaffolded', 'Created the initial GitHub Actions workflows for linting and testing. Deployment step is stubbed pending secrets setup.', '{"ci","devops"}', 'medium', '{".github/workflows/ci.yml",".github/workflows/deploy.yml"}', '[{"decision":"Matrix builds for CI","alternatives_considered":"Single-runner sequential jobs","rationale":"Cuts PR feedback time at the cost of higher parallel GitHub Actions minutes."}]', '{"Reviewed workflow config","Approved secrets plan"}', '{"dddddddd-0000-4000-8000-000000000001"}', '2020-07-11T18:47:32.000Z', '2020-08-20T19:29:35.000Z', DEFAULT, DEFAULT, '[]', NULL, NULL, 'Lint and test workflows run on every PR; production deploy is wired but awaits finalized secrets.', '[{"id":"ffffffff-1001-4000-8000-000000000001","objective_id":"ffffffff-1001-4000-8000-000000000001","index":0,"title":"CI workflow setup","state":"complete","position":0,"duration":"12m","events":1,"takeaway":"Lint and test jobs run on every pull request with cached dependencies.","body":"Configured GitHub Actions workflows for lint and test jobs mirroring what reviewers now see in file changes.","file_changes":[{"path":".github/workflows/ci.yml","status":"modified","additions":34,"deletions":8,"note":"Added cached install steps and a Node 20/22 matrix with fail-fast enabled."}],"action_required":[],"tradeoffs":[{"decision":"Cache node_modules between jobs","alternatives_considered":"Fresh install each job","rationale":"Speeds up CI significantly while accepting occasional cache staleness risk."}],"event_ids":["dddddddd-0000-4000-8000-000000000001"],"updated_at":"2026-03-26T09:55:00.000Z","agent_identifier":"Claude","model_identifier":null},{"id":"ffffffff-1002-4000-8000-000000000002","objective_id":"ffffffff-1002-4000-8000-000000000002","index":1,"title":"Deployment wiring","state":"complete","position":1,"duration":"7m","events":0,"takeaway":"Deploy job exists; production credentials remain gated behind security review.","body":"Added the deploy job structure and placeholders for secrets; wiring completes once credentials land.","file_changes":[{"path":".github/workflows/deploy.yml","status":"modified","additions":28,"deletions":0,"note":"Stubbed production deploy with branch guard on main only."}],"action_required":["Confirm production secret names with security"],"tradeoffs":[{"decision":"Gate deploy on main only","alternatives_considered":"Allow deploy from long-lived release branches","rationale":"Shrinks blast radius while agents iterate on feature branches."}],"event_ids":["dddddddd-0000-4000-8000-000000000001"],"updated_at":"2026-03-26T10:04:00.000Z","agent_identifier":"Claude","model_identifier":null}]', '[]', 1, 2, 3, '{"cccccccc-0000-4000-8000-000000000001"}'), ('28f2a137-3a27-550d-95fa-832ad097adfd', 1, 'aaaaaaaa-0000-4000-8000-000000000001', 'bbbbbbbb-0000-4000-8000-000000000002', NULL, NULL, 'Design tokens defined', 'Established the initial color palette and spacing scale. Typography tokens are pending font licensing confirmation.', '{"design","frontend"}', 'low', '{"tokens/colors.ts","tokens/spacing.ts"}', '[{"decision":"CSS custom properties for runtime theming","alternatives_considered":"JS-in-CSS token objects compiled at build time","rationale":"Keeps tokens consumable from plain CSS and Storybook without extra bundler plugins."}]', '{"Reviewed palette with design team"}', '{}', '2020-08-16T08:07:23.000Z', '2020-03-07T02:40:34.000Z', DEFAULT, DEFAULT, '[]', NULL, NULL, 'Color and spacing scales are drafted in code; typography tokens wait on font licensing.', '[{"id":"ffffffff-1003-4000-8000-000000000003","objective_id":"ffffffff-1003-4000-8000-000000000003","index":0,"title":"Design system tokens","state":"draft","position":0,"duration":null,"events":0,"takeaway":"Foundational palette and spacing are ready for component refactors.","body":"Define color, spacing, and typography tokens for the Alpha project so downstream components share one source of truth.","file_changes":[{"path":"tokens/colors.ts","status":"modified","additions":42,"deletions":6,"note":"Introduced semantic color roles mapped to brand primaries."},{"path":"tokens/spacing.ts","status":"modified","additions":18,"deletions":2,"note":"Added an 8px-based spacing ladder for layout primitives."}],"action_required":["Confirm font licensing before publishing typography tokens"],"tradeoffs":[],"event_ids":[],"updated_at":null,"agent_identifier":null,"model_identifier":null}]', '[]', 0, 2, 2, '{}'), ('b23c41a8-98c5-5998-aa1e-a9d63209dfc3', 1, 'aaaaaaaa-0000-4000-8000-000000000002', 'bbbbbbbb-0000-4000-8000-000000000004', NULL, NULL, 'PostHog SDK integrated', 'Installed and initialized PostHog in the Beta app. Key flows (signup, onboarding, checkout) are now instrumented.', '{"analytics","tracking"}', 'medium', '{"lib/analytics.ts","app/layout.tsx"}', '[{"decision":"Lazy-load PostHog on interaction","alternatives_considered":"Bundle SDK with the main layout chunk","rationale":"Avoids blocking first paint while still capturing high-intent flows early enough."}]', '{"Verified events in PostHog dashboard"}', '{}', '2020-02-18T01:05:36.000Z', '2020-06-18T06:02:16.000Z', DEFAULT, DEFAULT, '[]', NULL, NULL, 'Analytics client loads after first paint; primary funnels emit events in staging.', '[{"id":"ffffffff-1005-4000-8000-000000000005","objective_id":"ffffffff-1005-4000-8000-000000000005","index":0,"title":"Integrate analytics SDK","state":"draft","position":0,"duration":null,"events":0,"takeaway":"Core acquisition and monetization funnels now emit structured analytics events.","body":"Add PostHog analytics to the Beta project and instrument key user flows so product can measure activation.","file_changes":[{"path":"lib/analytics.ts","status":"modified","additions":120,"deletions":4,"note":"Wrapped PostHog init with lazy import and safe no-op when key missing."},{"path":"app/layout.tsx","status":"modified","additions":22,"deletions":0,"note":"Mounted provider boundary without blocking SSR."}],"action_required":[],"tradeoffs":[],"event_ids":[],"updated_at":null,"agent_identifier":"Claude","model_identifier":null}]', '[]', 0, 2, 1, '{}'), ('03001170-4b13-556d-a0ba-beccf9189e29', 1, 'aaaaaaaa-0000-4000-8000-000000000002', 'bbbbbbbb-0000-4000-8000-000000000005', NULL, NULL, 'Accessibility audit complete', 'Ran axe-core on all pages. Found 12 WCAG AA violations — 8 resolved, 4 deferred to next sprint pending design input.', '{"a11y","quality"}', 'high', '{"components/Button.tsx","components/Modal.tsx","app/page.tsx"}', '[{"decision":"Defer strict color-contrast fixes","alternatives_considered":"Ship temporary high-contrast theme overrides now","rationale":"Brand palette refresh lands next sprint; avoids thrashing components twice."}]', '{"Triaged violations with design","Merged accessibility fixes"}', '{}', '2020-03-19T02:39:08.000Z', '2020-10-10T21:24:11.000Z', DEFAULT, DEFAULT, '[]', NULL, NULL, 'Automated axe pass found twelve AA issues; most are fixed in UI primitives, a few wait on brand color decisions.', '[{"id":"ffffffff-1006-4000-8000-000000000006","objective_id":"ffffffff-1006-4000-8000-000000000006","index":0,"title":"Audit accessibility issues","state":"draft","position":0,"duration":null,"events":0,"takeaway":"Critical interactive components now meet keyboard and screen reader baselines.","body":"Run axe-core across all pages and resolve WCAG AA violations, prioritizing customer-facing flows first.","file_changes":[{"path":"components/Button.tsx","status":"modified","additions":36,"deletions":12,"note":"Added focus-visible ring and aria-busy during async actions."},{"path":"components/Modal.tsx","status":"modified","additions":28,"deletions":9,"note":"Trap focus and restore on close; labelled dialogs with aria-modal."},{"path":"app/page.tsx","status":"modified","additions":14,"deletions":3,"note":"Landmark roles and heading order fixes from audit report."}],"action_required":["Design sign-off on remaining contrast exceptions"],"tradeoffs":[],"event_ids":[],"updated_at":null,"agent_identifier":"Codex","model_identifier":null}]', '[]', 0, 3, 3, '{}');
